import type { Flashcard } from './types';

// Phase 2 expansion: fc-065 to fc-149 (85 new cards)
// Covers all identified content gaps from audit
export const expandedFlashcards: Flashcard[] = [

  // ===================== WEEK 1: DEEP ETHICS EXPANSION =====================
  { id: 'fc-065', week: 'week1', topic: 'Ethical Theories', front: 'What is Kant\'s Categorical Imperative and how does it apply to professional computing?', back: '1. Universalisability: act only on maxims you could will to be universal law. 2. Humanity Formula: treat persons never merely as means but always also as ends. Computing application: you cannot use user data as raw material for profit without treating users as ends in themselves. Test: "What if every developer did this?" — if the answer destroys the practice, the action is impermissible.', type: 'framework', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-066', week: 'week1', topic: 'Ethical Theories', front: 'What is the difference between Act and Rule Utilitarianism?', back: 'Act Utilitarianism: each individual act is evaluated for the utility it produces — maximise utility case by case. Rule Utilitarianism: identify rules that if generally followed would produce maximum utility. Relevance: Act Util could justify one privacy violation that "saves many." Rule Util argues that a general rule permitting this would erode all privacy trust — so the rule against violations maximises long-term utility.', type: 'definition', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-067', week: 'week1', topic: 'Ethical Theories', front: 'What is social contract theory and how does it ground computing ethics?', back: 'Rawls/Locke/Rousseau: society is a hypothetical agreement under which individuals accept constraints in exchange for mutual benefit. Computing professionals are granted elevated privileges (access to critical systems, personal data) under an implicit social contract. Violation of user trust breaks that contract, delegitimising the profession\'s claim to self-regulation.', type: 'definition', difficulty: 'hard', examRelevance: 'medium' },
  { id: 'fc-068', week: 'week1', topic: 'BCS Code', front: 'Name and explain three specific provisions under BCS s.1 (Public Interest)', back: '1. "You shall have due regard for public health, privacy, security and wellbeing of others and the environment" — safety-critical systems require professional veto. 2. "You shall have due regard for the legitimate rights of third parties" — users are third parties relative to employer/client. 3. "You shall act with integrity in your relationships with all stakeholders" — transparency obligation even when inconvenient.', type: 'law', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-069', week: 'week1', topic: 'BCS Code', front: 'Distinguish positive duties from negative duties in the BCS Code', back: 'Negative duty (prohibitive): "Do NOT do harm" — refrain from releasing unsafe software, do not deceive clients. Positive duty (active): "DO act to prevent harm" — actively escalate if you discover data breach, proactively improve security. Weak students only identify negative duties. Distinction answers note both types and argue positive duties are more demanding — requiring professional courage.', type: 'application', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-070', week: 'week1', topic: 'ACM Code', front: 'What are ACM Code Principles 1.1 and 1.2?', back: '1.1 Contribute to society and human well-being: prioritise public good, assess impact beyond technical compliance. 1.2 Avoid harm: report risks even when unwelcome; "if a developer cannot avoid harm, they should take the most ethical action possible." These two principles explain why ACM supports whistleblowing — the obligation to avoid harm can override employer loyalty.', type: 'framework', difficulty: 'medium', examRelevance: 'high' },
  { id: 'fc-071', week: 'week1', topic: 'Whistleblowing Law', front: 'What is a "protected disclosure" under PIDA 1998?', back: 'Public Interest Disclosure Act 1998 protects workers from detriment/dismissal for disclosing: criminal offences, failure to comply with legal obligations, miscarriages of justice, health/safety dangers, environmental damage, or deliberate concealment. Must be: reasonable belief in truth, made to appropriate person. NOT protected: malicious disclosures, matters outside the six categories, disclosures for personal gain.', type: 'law', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-072', week: 'week1', topic: 'Professional Standards', front: 'What is the Blyth v Birmingham Waterworks reasonableness standard?', back: 'Blyth v Birmingham Waterworks Co [1856]: negligence is "the omission to do something which a reasonable man, guided upon those considerations which ordinarily regulate the conduct of human affairs, would do, or doing something which a prudent and reasonable man would not do." Applied to computing: computing professionals are judged against what a REASONABLE COMPUTING PROFESSIONAL would do — not what an expert would do, but not what a layperson would do either. Informs professional negligence claims.', type: 'law', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-073', week: 'week1', topic: 'Professional Standards', front: 'What is the difference between aspirational and minimum ethics in professional codes?', back: 'Minimum ethics: legally required standards — do not break the law, do not defraud clients. Aspirational ethics: what the profession strives toward — proactively improving user privacy, advocating for ethical AI, speaking up against exploitative practices. The ELGPC hierarchy shows compliance is the floor. BCS and ACM both articulate aspirational standards — 90%+ answers discuss BOTH and note the tension when aspirational standards require personal sacrifice.', type: 'application', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-074', week: 'week1', topic: 'Stakeholders', front: 'What is stakeholder analysis and why must computing professionals perform it?', back: 'Identifying all parties who have an interest in or are affected by a technical system or decision — beyond the paying client. Primary stakeholders: direct users, client, employer. Secondary: third parties whose data is processed, society (AI bias victims), future users. Negative stakeholders: bad actors, regulators opposing deployment. 90%+ answers map harms AND benefits across ALL stakeholder categories, not just the primary user.', type: 'framework', difficulty: 'medium', examRelevance: 'high' },
  { id: 'fc-075', week: 'week1', topic: 'Haugen Deep', front: 'What specific sequence did Frances Haugen follow before going public?', back: '1. Raised concerns internally to direct management — ignored. 2. Filed SEC whistleblower complaints (9 separate submissions) before going to media. 3. Provided documentation to Wall Street Journal and then Congressional testimony. This sequence is legally important: SEC filing first establishes protected disclosure; public media is the LAST step. Directly demonstrates BCS escalation ladder compliance. She received legal protection precisely because she followed the sequence.', type: 'casestudy', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-076', week: 'week1', topic: 'Ethical Tensions', front: 'What is the loyalty-honesty tension in computing ethics?', back: 'Computing professionals owe loyalty to employer (contract, fiduciary) but honesty to all stakeholders (professional codes). These conflict when employer asks for non-disclosure, overstating product capabilities, or suppressing safety findings. BCS s.1 resolves: public interest overrides employer loyalty when they conflict. A professional cannot claim "I was just following orders" — this defence is explicitly rejected in Nuremberg jurisprudence and implicitly in professional codes.', type: 'application', difficulty: 'hard', examRelevance: 'high' },

  // ===================== WEEK 2: GDPR DEEP EXPANSION =====================
  { id: 'fc-077', week: 'week2', topic: 'GDPR Rights', front: 'What are the conditions for the right to erasure under Art. 17 GDPR?', back: 'RIGHT TO ERASURE applies when: (1) data no longer necessary for original purpose; (2) consent withdrawn and no other lawful basis; (3) data subject objects and no overriding legitimate interests; (4) data unlawfully processed; (5) legal obligation to erase. EXCEPTIONS: freedom of expression, legal obligations, public interest in research/statistics, legal claims. "Right to be forgotten" is not absolute — it is a qualified right.', type: 'law', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-078', week: 'week2', topic: 'GDPR Rights', front: 'When does Art. 22 (automated decision-making) apply?', back: 'Applies to decisions SOLELY based on automated processing with SIGNIFICANT EFFECT on individuals — credit scoring, hiring, medical diagnosis, fraud detection. The right: humans must be able to request human review of the decision. Exceptions: necessary for contract, authorised by law, explicit consent. AI applying ethics: automated hiring must have human review. Weak answers describe AI generally; strong answers cite Art. 22 and explain "solely automated" and "significant effect" thresholds.', type: 'law', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-079', week: 'week2', topic: 'GDPR Process', front: 'When is a Data Protection Impact Assessment (DPIA) mandatory?', back: 'Art. 35 mandates DPIA before processing that is "likely to result in high risk" to individuals. Triggers: systematic large-scale processing of special categories; systematic large-scale monitoring (CCTV, employee tracking); new technologies; profiling with significant effects. Process: describe processing → assess necessity/proportionality → identify risks → measures to address risks. DPIA is not optional for high-risk processing — it is a legal requirement.', type: 'law', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-080', week: 'week2', topic: 'GDPR Compliance', front: 'Explain the three-part legitimate interests test (Art. 6(1)(f))', back: 'STEP 1 — Purpose Test: Is there a genuine legitimate interest? (commercial, security, fraud prevention). STEP 2 — Necessity Test: Is the processing necessary to achieve that interest, or could it be achieved less intrusively? STEP 3 — Balancing Test: Does the interest override the data subject\'s rights and freedoms? Factors: reasonable expectations of data subjects, nature of data, scale of impact. If ANY step fails, the basis is invalid. Legitimate interests is NOT a catch-all — it fails for marketing without transparency.', type: 'framework', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-081', week: 'week2', topic: 'GDPR Breach', front: 'What are the data breach notification obligations under GDPR Arts. 33 and 34?', back: 'Art. 33 — to supervisory authority: within 72 HOURS of becoming aware, unless "unlikely to result in a risk." Must include: nature of breach, categories/approximate number affected, likely consequences, measures taken. Art. 34 — to individuals: "without undue delay" when breach is "likely to result in HIGH RISK" to their rights. No notification when: data encrypted, controller took measures to ensure risk not materialised. The 72-hour clock starts when the controller becomes AWARE, not when the breach occurs.', type: 'law', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-082', week: 'week2', topic: 'Cookie Law', front: 'What law governs cookie consent in the UK?', back: 'Privacy and Electronic Communications Regulations 2003 (PECR) — not GDPR. PECR requires: informed consent before setting non-essential cookies; clear explanation of what cookies do; genuine choice (decline option must be as easy as accept). GDPR applies to processing data collected via cookies. Common mistake: citing GDPR for cookies. Correct: PECR (consent mechanism) + GDPR (processing the collected data). ICO has fined multiple organisations for cookie non-compliance.', type: 'law', difficulty: 'medium', examRelevance: 'medium' },
  { id: 'fc-083', week: 'week2', topic: "Children's Privacy", front: "What is the UK Age Appropriate Design Code?", back: 'ICO\'s Children\'s Code (2021): if an online service is "likely to be accessed" by children under 18, it must: apply highest privacy settings by default; use children\'s data only for direct service benefit; not profile children for behavioural advertising; not nudge children to provide more data. TikTok\'s £12.7M fine (2023) was partly under this code — inadequate age verification, children\'s data used for recommendation profiling.', type: 'law', difficulty: 'medium', examRelevance: 'high' },
  { id: 'fc-084', week: 'week2', topic: 'International Transfers', front: 'What mechanisms permit UK-to-US personal data transfers post-Brexit?', back: '1. UK-US Data Bridge (formerly UK GDPR adequacy extension, 2023): US organisations self-certify to principles; UK organisations can transfer to certified entities. 2. Standard Contractual Clauses (SCCs): contractual obligations binding both parties. 3. Binding Corporate Rules: for intra-group transfers. The US is NOT on the UK\'s adequacy list by default — must use one of these mechanisms. Post-Schrems II, transfers without mechanism = unlawful.', type: 'law', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-085', week: 'week2', topic: 'Data Roles', front: 'Distinguish data controller from data processor under UK GDPR', back: 'DATA CONTROLLER: determines the purposes and means of processing — the primary legal responsibility holder. DATA PROCESSOR: processes data on behalf of the controller — must follow controller instructions; cannot process for own purposes. Key consequence: controllers are liable to data subjects; processors face contract liability to controllers. One entity can be controller for one purpose and processor for another. Cloud providers are often processors; the organisation deploying the cloud service is the controller.', type: 'definition', difficulty: 'medium', examRelevance: 'high' },
  { id: 'fc-086', week: 'week2', topic: 'SAR Process', front: 'Describe the Subject Access Request (SAR) process and timescale', back: 'A SAR is a request for a copy of all personal data an organisation holds about you. TIMESCALE: must respond within 1 CALENDAR MONTH (extendable by 2 months for complex/numerous requests with explanation). CONTENT: copy of all personal data, purposes of processing, categories, recipients, retention periods, rights information. COST: FREE (cannot charge unless requests are "manifestly unfounded or excessive"). Common ICO enforcement area.', type: 'law', difficulty: 'medium', examRelevance: 'medium' },
  { id: 'fc-087', week: 'week2', topic: 'GDPR Enforcement', front: 'What are the two tiers of GDPR fines and how do they differ?', back: 'LOWER TIER (£8.7M or 2% global annual turnover — whichever higher): violations of processor obligations, DPO duties, certification bodies. UPPER TIER (£17.5M or 4% global annual turnover — whichever higher): violations of basic principles (Art. 5, 6, 9), data subjects\' rights, international transfer rules. Facebook\'s Meta fined €1.2B by Irish DPC (2023) for US data transfers. ICO upper tier maximum in UK.', type: 'law', difficulty: 'medium', examRelevance: 'high' },

  // ===================== WEEK 3: IP DEEP EXPANSION =====================
  { id: 'fc-088', week: 'week3', topic: 'Copyright Exceptions', front: 'What are the five main fair dealing exceptions in UK copyright law?', back: '1. Research and private study (non-commercial). 2. Criticism, review, and reporting current events — "sufficient acknowledgment" required. 3. Caricature, parody, pastiche — proportionate use. 4. Quotation — permitted if justified by purpose. 5. Text and Data Mining — for non-commercial research. Note: UK fair dealing is narrower than US "fair use" — it is SPECIFIC CATEGORIES, not a general "fairness" test. Crucial for AI training data debates.', type: 'law', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-089', week: 'week3', topic: 'Moral Rights', front: 'What are moral rights in copyright law (CDPA 1988)?', back: 'Rights that protect the author\'s personal relationship to their work, independent of economic rights. s.77: Right of attribution — to be identified as author. s.80: Right of integrity — right to object to derogatory treatment. s.85: Right against false attribution. CANNOT BE SOLD — they belong permanently to the author (unlike economic rights which can be assigned). However, employees can WAIVE moral rights (unlike economic rights which employers automatically own). Key for developer credits in software.', type: 'law', difficulty: 'hard', examRelevance: 'medium' },
  { id: 'fc-090', week: 'week3', topic: 'Database Rights', front: 'What is the sui generis database right?', back: 'A separate IP right (EU Database Directive 1996, implemented CDPA 1988) protecting the substantial investment in creating a database — even if the content itself is not original. Duration: 15 years from creation/last substantial update. Infringes: extraction or re-utilisation of a substantial part. Critical for scraping cases: even public data may be protected by database right if extraction is substantial. Different from copyright — focuses on investment, not creativity.', type: 'law', difficulty: 'hard', examRelevance: 'medium' },
  { id: 'fc-091', week: 'week3', topic: 'Employee IP', front: 'Who owns software created by an employee during employment?', back: 'CDPA 1988 s.11(2): where a work is made by an EMPLOYEE in the course of employment, the employer is the FIRST OWNER of copyright, unless agreement to contrary. "In the course of employment" = during normal duties. CONTRACTORS/FREELANCERS: own their own IP by default — assignment clause required in contract. Patent Act 1977 s.39: employee inventions in course of normal duties are employer-owned; inventions in personal time are employee-owned. This is a common commercial dispute.', type: 'law', difficulty: 'medium', examRelevance: 'high' },
  { id: 'fc-092', week: 'week3', topic: 'Licensing', front: 'Compare GPL, LGPL, MIT, and Apache 2.0 licences', back: 'GPL (copyleft): derivative works must be GPL — "viral." Cannot mix with proprietary. LGPL (lesser copyleft): allows linking from proprietary code; only modifications to the LGPL library must be open-sourced. MIT (permissive): use in any project, open or commercial, with attribution only. Apache 2.0 (permissive + patent): like MIT but also grants patent rights from contributors. For commercial software: MIT/Apache safe; GPL risky; LGPL depends on integration type.', type: 'framework', difficulty: 'medium', examRelevance: 'high' },
  { id: 'fc-093', week: 'week3', topic: 'Trade Secrets', front: 'How are trade secrets protected in the UK?', back: 'No registration required. Protected by: (1) Contract law — NDAs, confidentiality clauses. (2) Law of confidence — breach of confidence tort (misuse of confidential information). (3) Trade Secrets (Enforcement, etc.) Regulations 2018 (implementing EU Directive). Requirements: information is secret, has commercial value, reasonable steps taken to maintain secrecy. Unlike patents, trade secrets can last indefinitely (Coca-Cola formula) but lost if independently discovered or disclosed.', type: 'law', difficulty: 'medium', examRelevance: 'medium' },
  { id: 'fc-094', week: 'week3', topic: 'Patent Duration', front: 'Compare duration: copyright, patent, trade mark, unregistered design', back: 'Copyright: life of author + 70 years (works made for hire: 70 years from publication/creation). Patent: 20 years from filing date (annual renewal fees required). Registered trade mark: 10 years, renewable indefinitely every 10 years. Unregistered design right (UK): 15 years from creation or 10 years after first marketing. Database right: 15 years from last substantial investment. This is high-value MCQ material — durations are frequently tested.', type: 'framework', difficulty: 'medium', examRelevance: 'high' },
  { id: 'fc-095', week: 'week3', topic: 'Reverse Engineering', front: 'Is reverse engineering of software lawful in the UK?', back: 'Limited statutory exception under Computer Programs Directive (implemented CDPA 1988): permitted only (1) to achieve interoperability with independently created programs, (2) by a person lawfully entitled to use the program, (3) where the information is not readily available, and (4) acts limited to what is necessary. CANNOT be contracted out — any contract term restricting this specific exception is void. Does not extend to: exposing security vulnerabilities, bypassing DRM.', type: 'law', difficulty: 'hard', examRelevance: 'medium' },

  // ===================== WEEK 5: GOVERNANCE DEEP EXPANSION =====================
  { id: 'fc-096', week: 'week5', topic: 'ISO 27001', front: 'What is ISO 27001 and how does it relate to information governance?', back: 'ISO/IEC 27001: international standard for Information Security Management Systems (ISMS). Requires: risk assessment → select controls from Annex A → implement → monitor and review → continual improvement (Plan-Do-Check-Act cycle). NOT a law — but often required by contracts and demonstrates IG accountability (GDPR P7). Certification shows prospective clients and regulators that security is systematic, not ad hoc. Annex A covers 93 controls across 4 themes.', type: 'framework', difficulty: 'medium', examRelevance: 'medium' },
  { id: 'fc-097', week: 'week5', topic: 'NIST Framework', front: 'What are the five functions of the NIST Cybersecurity Framework?', back: 'IDENTIFY → PROTECT → DETECT → RESPOND → RECOVER. Not prescriptive — describes outcomes, not specific controls. Used widely in US critical infrastructure; increasingly referenced in UK. Each function has categories: Identify includes asset management, risk assessment. Detect includes anomaly detection. Respond includes communications and analysis. Recovery includes restoration. IG application: maps to the information lifecycle and LORS failure prevention.', type: 'framework', difficulty: 'medium', examRelevance: 'medium' },
  { id: 'fc-098', week: 'week5', topic: 'Data Classification', front: 'What are the HMG data classification levels and what do they mean?', back: 'OFFICIAL: default for most public sector data — must be handled appropriately. OFFICIAL-SENSITIVE: higher risk subset requiring additional care. SECRET: very serious damage if compromised — small audience, need-to-know basis. TOP SECRET: exceptionally grave damage — highest protection. For organisations: data classification levels (Public, Internal, Confidential, Restricted) trigger different access controls, retention rules, and transmission requirements. Classification is foundational to defensible IG.', type: 'framework', difficulty: 'medium', examRelevance: 'medium' },
  { id: 'fc-099', week: 'week5', topic: 'Accountability in IG', front: 'Distinguish accountability from responsibility in information governance', back: 'RESPONSIBILITY: the obligation to perform a task or act — can be delegated (e.g., a developer "responsible" for a database). ACCOUNTABILITY: the obligation to answer for an outcome — cannot be delegated (the CISO is accountable for the breach even if a junior caused it). DPO and CISO roles are ACCOUNTABILITY roles — they bear ultimate answerability even if they did not personally make all decisions. Post Office Horizon: accountability gap — everyone responsible, nobody accountable.', type: 'application', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-100', week: 'week5', topic: 'Retention', front: 'Why are data retention schedules a core component of IG?', back: 'Data retained beyond necessity: (1) increased breach risk — more data = larger attack surface. (2) GDPR P5 (storage limitation) breach — ICO fines. (3) Subject to SAR — more data means more complex/expensive compliance. (4) Legal liability — historical data discoverable in litigation. A retention schedule specifies: data type → retention period → authority for that period → disposal method. Defensible disposal: documented proof of deletion creates legal protection if data is later sought.', type: 'framework', difficulty: 'medium', examRelevance: 'high' },
  { id: 'fc-101', week: 'week5', topic: 'Freedom of Information', front: 'What is the Freedom of Information Act 2000 and who does it bind?', back: 'FOIA 2000 gives any person the right to request recorded information held by UK public authorities. Timescale: 20 working days. Exemptions: national security, commercial interests, personal data (GDPR applies instead), ongoing investigations. Bodies subject: government departments, NHS, police, universities, schools. Private companies: NOT subject unless performing public functions. ICO enforces FOIA. Interaction: a FOIA request for personal data triggers GDPR, not FOIA.', type: 'law', difficulty: 'medium', examRelevance: 'medium' },
  { id: 'fc-102', week: 'week5', topic: 'Red Teaming Deep', front: 'What is the difference between a vulnerability assessment and a penetration test?', back: 'VULNERABILITY ASSESSMENT: automated scanning for known vulnerabilities — broad coverage, low depth. Lists what exists. PENETRATION TEST: manual + automated exploitation — attempts to actually compromise the system. Demonstrates what can be achieved by an attacker. Neither is "red teaming" — red teaming includes social engineering, physical access, and tests human responses. Governance application: organisations at IG maturity level 3+ should conduct regular penetration tests; maturity level 4+ includes red teaming.', type: 'definition', difficulty: 'medium', examRelevance: 'medium' },
  { id: 'fc-103', week: 'week5', topic: 'Digital Twin', front: 'What is a digital twin in the context of red teaming and IG?', back: 'A real-time digital replica of an operational system used for simulation, testing, and red teaming without risking the live environment. Enables: testing failure scenarios (ransomware response, data breach simulation), governance stress-testing, process optimisation. Ethical consideration: digital twins of people (patient records + behaviour models) raise significant privacy concerns — GDPR requires legal basis for the model creation. NHS digital twin programmes require DPIA.', type: 'application', difficulty: 'hard', examRelevance: 'medium' },

  // ===================== WEEK 6: CYBERSECURITY DEEP EXPANSION =====================
  { id: 'fc-104', week: 'week6', topic: 'Zero-Day', front: 'What is a zero-day vulnerability and what are the ethical dilemmas around it?', back: 'A software flaw unknown to the vendor — no patch exists. Value: immense to nation-states for undetected exploitation. Ethical tension: (1) responsible disclosure — report to vendor → patch → public disclosure; (2) sale to bug brokers (Zerodium pays up to $2.5M per iOS zero-day) — enables surveillance; (3) stockpiling by governments (NSA lost EternalBlue → WannaCry). Professional obligation under BCS s.1: disclose responsibly, do not sell to governments to enable illegal surveillance.', type: 'application', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-105', week: 'week6', topic: 'Social Engineering', front: 'Name and explain five social engineering attack types', back: 'Phishing: mass email impersonating trusted entity for credentials. Spear phishing: targeted at specific individual using personal detail. Whaling: spear phishing targeting executives. Vishing: voice call impersonation (phone scams). Pretexting: fabricated scenario to extract information (fake IT support). Smishing: SMS-based phishing. Baiting: physical media (infected USB left in car park). All exploit human psychology, not technology — PTLN test applies to defences: transparent policies + necessary training + proportionate controls.', type: 'framework', difficulty: 'medium', examRelevance: 'high' },
  { id: 'fc-106', week: 'week6', topic: 'Bug Bounty', front: 'What is a bug bounty programme and what are its legal boundaries?', back: 'A formal scheme where an organisation invites external researchers to find and report vulnerabilities in exchange for payment. Provides: legal authorisation (CMA protection via explicit consent), financial incentive for responsible disclosure, improved security posture. Boundaries: scope clearly defined — testing outside scope = unauthorised access = CMA s.1 offence even if well-intentioned. Hunter and target must agree on: scope, rules of engagement, safe harbour, payment structure. HackerOne and Bugcrowd are major platforms.', type: 'application', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-107', week: 'week6', topic: 'Incident Response', front: 'Name the six phases of the incident response lifecycle', back: 'PREPARATION → IDENTIFICATION → CONTAINMENT → ERADICATION → RECOVERY → LESSONS LEARNED. Preparation: policies, tools, training, CSIRT team. Identification: detect and classify incident. Containment: isolate affected systems to prevent spread. Eradication: remove root cause (malware, vulnerability). Recovery: restore normal operations, monitor for recurrence. Lessons Learned: post-incident review, update defences. GDPR 72-hour notification clock starts at Identification phase.', type: 'framework', difficulty: 'medium', examRelevance: 'high' },
  { id: 'fc-108', week: 'week6', topic: 'OWASP', front: 'What are the top three OWASP vulnerabilities and their computing ethics implications?', back: 'A1: Broken Access Control — failing to restrict what authenticated users can do. Professional obligation to fix before deployment. A3: Injection (SQL/Command) — allows attackers to execute unintended queries. A7: Identification and Authentication failures — poor session management, credential exposure. Ethics: shipping code with known critical vulnerabilities is professional negligence under BCS s.3 (professional competence). "We didn\'t have time to fix it" does not satisfy the Blyth reasonableness standard.', type: 'application', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-109', week: 'week6', topic: 'NIS Regulations', front: 'What are the NIS Regulations 2018 and who do they apply to?', back: 'Network and Information Systems Regulations 2018 — UK implementation of EU NIS Directive. Applies to: Operators of Essential Services (OES: energy, transport, health, water, digital infrastructure) and Relevant Digital Service Providers (online marketplaces, search engines, cloud services). Requires: appropriate technical/organisational security measures; incident notification within 72 hours. NCSC is the competent authority for many sectors. Fines: up to £17M. Post-Brexit UK update: NIS2 implementation pending.', type: 'law', difficulty: 'medium', examRelevance: 'high' },
  { id: 'fc-110', week: 'week6', topic: 'Cryptography', front: 'Distinguish symmetric and asymmetric encryption and their use cases', back: 'SYMMETRIC: same key for encrypt/decrypt — fast, but key distribution problem. AES-256 standard. Use case: encrypting data at rest, disk encryption. ASYMMETRIC: public/private key pair — public key encrypts, private key decrypts. RSA, ECC. Use case: secure key exchange (TLS handshake), digital signatures, email encryption (PGP). TLS PROTOCOL: uses asymmetric for key exchange, then symmetric for session data — best of both. Governance: encryption at rest and in transit required for GDPR P6 compliance.', type: 'framework', difficulty: 'medium', examRelevance: 'medium' },
  { id: 'fc-111', week: 'week6', topic: 'Ransomware', front: 'Explain the ransomware kill chain and professional response', back: 'Attack lifecycle: Phishing/RDP exploit → install loader → deploy ransomware → encrypt files + exfiltrate data (double extortion) → ransom demand. Professional response: (1) DO NOT PAY — funds criminal activity, no guarantee of recovery, may breach OFAC sanctions. (2) Restore from immutable backups. (3) Report to NCSC + ICO (if personal data involved — 72-hour clock). (4) Engage incident response firm. (5) NIS notification if OES. Common failure: no offline immutable backups = paying becomes the only option.', type: 'application', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-112', week: 'week6', topic: 'Pen Test Legal', front: 'What must be agreed in a penetration test engagement before testing begins?', back: 'ESSENTIAL DOCUMENTATION: (1) Letter of Authorisation — signed by system owner, defines scope. (2) Rules of Engagement — what testing is in/out of scope, hours, communication protocol. (3) Scoping document — IP ranges, domains, exclusions. (4) Non-Disclosure Agreement — protects sensitive findings. Without LoA: CMA S.1 applies regardless of good intentions. "I thought I had permission" is not a defence. Professional testers require signed authorisation before ANY testing begins.', type: 'law', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-113', week: 'week6', topic: 'Supply Chain', front: 'What is a supply chain attack and why is it so dangerous?', back: 'Compromising a trusted third-party component/vendor to gain access to the primary target. Danger: target\'s defences assume trustworthy code from signed/verified vendor. Examples: SolarWinds (2020) — 18,000 orgs compromised via trojanised IT update; Bybit (2025) — UI manipulation via compromised signing interface; XZ Utils (2024) — backdoor inserted into Linux compression library. CMA applies to the attacker; governance implication: organisations must treat SUPPLY CHAIN as part of their attack surface.', type: 'casestudy', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-114', week: 'week6', topic: 'Digital Forensics', front: 'What are the key principles of digital forensics?', back: 'ADMISSIBILITY: evidence must be acquired legally — warrant or consent required. INTEGRITY: hash values (SHA-256) prove evidence unchanged. CHAIN OF CUSTODY: documented record of who handled evidence and when. AUTHENTICITY: provenance established. First responder principle: do not alter the live system — image/snapshot first, then analyse copy. Write blockers prevent modification during imaging. Forensic investigation without following these principles produces inadmissible evidence — cannot support criminal prosecution.', type: 'framework', difficulty: 'medium', examRelevance: 'medium' },

  // ===================== WEEK 9: WORKPLACE DEEP EXPANSION =====================
  { id: 'fc-115', week: 'week9', topic: 'Employment Law', front: 'What are the key provisions of the Employment Rights Act 1996 relevant to computing professionals?', back: 'ERA 1996 provides: unfair dismissal protection after 2 years employment; wrongful dismissal (breach of contract); right to written statement of employment particulars; minimum notice periods. For computing: dismissal for whistleblowing is automatically unfair (PIDA 1998 — Day 1 right); dismissal for refusing to carry out illegal instructions may be automatically unfair. Professional code obligations can create conflict with contractual duties — ERA protects employees who comply with professional codes.', type: 'law', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-116', week: 'week9', topic: 'Equality Act', front: 'What are the nine protected characteristics under the Equality Act 2010?', back: 'Age; Disability; Gender reassignment; Marriage/civil partnership; Pregnancy/maternity; Race; Religion/belief; Sex; Sexual orientation. Computing relevance: algorithmic discrimination (hiring AI that disadvantages women or ethnic minorities may breach Equality Act); accessibility (products must be accessible to disabled users — reasonable adjustments duty); Sam\'s 1st Day — neurodiversity as disability requiring reasonable adjustments.', type: 'law', difficulty: 'medium', examRelevance: 'high' },
  { id: 'fc-117', week: 'week9', topic: 'Constructive Dismissal', front: 'What is constructive dismissal and when does it apply?', back: 'Employee resigns in response to employer\'s fundamental breach of contract — treated as dismissal by the employer. Applies when: employer unilaterally changes key terms; bullying creates intolerable working conditions; employer systematically breaches duty of mutual trust and confidence. Computing relevance: if an employer insists a computing professional perform illegal activities (bypassing CMA, GDPR violations) and the professional refuses and is forced to resign — potential constructive dismissal claim. The professional code obligation reinforces the employment law claim.', type: 'law', difficulty: 'hard', examRelevance: 'medium' },
  { id: 'fc-118', week: 'week9', topic: 'Remote Monitoring', front: 'How do GDPR and RIPA apply to monitoring remote workers?', back: 'Remote work does not reduce employee privacy rights. Keystroke logging / screen recording of home computers: (1) likely to capture personal data (financial, medical) if on personal device — very high GDPR threshold; (2) TLBP Regulations: must notify employees, must be proportionate — blanket remote monitoring rarely proportionate; (3) BYOD (Bring Your Own Device): GDPR P3 minimisation — cannot scan personal device unless clearly contractually agreed and proportionate. ICO guidance: transparency mandatory; covert monitoring of home workers almost never lawful.', type: 'application', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-119', week: 'week9', topic: 'Social Media', front: 'What are the legal and professional issues around employee social media use?', back: 'Employer rights: monitor public posts (proportionate); discipline for posts bringing organisation into disrepute (ACAS code). Employee rights: personal social media outside work is private (GDPR, ECHR Art. 8); trade union activity protected. Tension: "brand ambassador" expectation vs private life. Computing professionals: social media posts about employer\'s systems or security vulnerabilities may breach confidentiality — potentially criminal (CMA s.3A if disclosing exploit details; breach of confidence tort). BCS Code s.6: duty to maintain confidentiality.', type: 'application', difficulty: 'hard', examRelevance: 'medium' },
  { id: 'fc-120', week: 'week9', topic: 'ACAS Code', front: 'What are the key requirements of the ACAS Code of Practice on Disciplinary Procedures?', back: 'Before disciplinary action: investigate fairly; inform employee in writing of alleged misconduct; allow reasonable time to prepare. Hearing: employee right to be accompanied (colleague/trade union rep); management presents case; employee responds. Decision: verbally communicated then confirmed in writing; proportionate to misconduct. Appeal: right to appeal to more senior manager. Failure to follow ACAS Code: employment tribunal can INCREASE award by up to 25% (employee) or REDUCE by 25% (employer fault). Procedural fairness matters as much as substantive misconduct.', type: 'framework', difficulty: 'medium', examRelevance: 'high' },
  { id: 'fc-121', week: 'week9', topic: 'Right to Disconnect', front: 'Is there a right to disconnect in the UK and what are the professional obligations?', back: 'UK has NO statutory right to disconnect (unlike France, Ireland, Belgium). BUT: Working Time Regulations 1998 provide 11 hours minimum daily rest; 48-hour average working week (opt-out possible). Professional obligation: BCS s.6 (public interest includes employee wellbeing); computing professionals who design always-on systems with notification pressure may be contributing to employee harm. Ethics beyond law: organisational culture of "always on" may breach duty of care (health and safety).', type: 'application', difficulty: 'hard', examRelevance: 'medium' },
  { id: 'fc-122', week: 'week9', topic: 'Professional Identity', front: 'What is the "computing professional identity" issue raised by Sam\'s 1st Day?', back: 'Sam\'s 1st Day shows systems designed without consulting the humans who use them. Computing professionals who design onboarding systems bear professional responsibility for the human impact — they are not neutral technicians. This mirrors the asymmetric power argument: the developer who builds an inaccessible portal causes real harm to real people without meeting them. BCS Code requires awareness of this impact. The module\'s central thesis: professional identity = responsibility for human consequences.', type: 'application', difficulty: 'hard', examRelevance: 'high' },

  // ===================== CROSS-CUTTING EDGE CASES =====================
  { id: 'fc-123', week: 'week1', topic: 'Edge Cases', front: 'Is it ethical to comply with a law that is itself unethical?', back: 'This is the Nazi Jurisprudence problem (Nuremberg). Positivism says law is law regardless of content; Natural Law says unjust law is no law at all. Professional codes resolve this: BCS s.1 says public interest is paramount — a computing professional cannot claim "I followed the law" as a defence when the law authorised unethical surveillance or discriminatory systems. This is why professional ethics sits ABOVE legal compliance in the ELGPC hierarchy.', type: 'application', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-124', week: 'week2', topic: 'Edge Cases', front: 'Is scraping publicly available social media data a GDPR violation?', back: 'YES — if it constitutes processing of personal data. "Publicly available" does not mean "freely usable." GDPR applies to ANY processing of personal data, regardless of source. Key issues: original purpose limitation (users didn\'t consent to scraping); aggregation problem (public posts + timestamps + locations = surveillance); special category data (opinions, photos may reveal race, religion, health). Twitter/LinkedIn scraping: repeatedly investigated by multiple DPAs. Professional obligation: assess lawful basis before any large-scale social media data project.', type: 'application', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-125', week: 'week3', topic: 'Edge Cases', front: 'Who owns code generated by GitHub Copilot during employment?', back: 'COMPLEX ANSWER: (1) the employer likely owns it if generated during working hours using employment resources — CDPA s.11(2). (2) If the generated code reproduces copyrighted training data — potential infringement liability falls on the employer (downstream use). (3) GitHub/Microsoft claim licence rights over outputs — contract terms. (4) US court cases (Doe v GitHub 2023) ongoing. Professional obligation: declare Copilot use; check employer IP policy; consider attribution; assess reproduction risk.', type: 'application', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-126', week: 'week6', topic: 'Edge Cases', front: 'A security researcher discovers child abuse material (CSAM) during an authorised penetration test. What must they do?', back: 'MANDATORY REPORTING. Protection of Children Act 1978 / Sexual Offences Act 2003: possession even incidentally constitutes a criminal offence unless immediate reporting. Professional obligation: (1) STOP the penetration test at that point — do not proceed; (2) do not access or examine further; (3) report immediately to police (CEOP/Action Fraud); (4) preserve evidence without contamination; (5) notify client organisation. Authorisation letter does NOT cover possession of CSAM. Professional codes are superseded by criminal law reporting obligations.', type: 'application', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-127', week: 'week5', topic: 'Edge Cases', front: 'Can an organisation comply with UK GDPR while also being ISO 27001 certified?', back: 'YES — and they should complement each other. ISO 27001 provides the SECURITY MANAGEMENT SYSTEM; GDPR requires the security outcome. Synergies: ISO 27001 risk assessment → identifies GDPR Art. 35 DPIA triggers; Annex A controls → implement GDPR P6 (integrity and confidentiality); ISMS documentation → demonstrates GDPR P7 accountability. Gap: ISO 27001 doesn\'t cover data subject rights, lawful basis, or privacy — must supplement with GDPR-specific programme. Together they constitute gold-standard IG.', type: 'application', difficulty: 'hard', examRelevance: 'medium' },
  { id: 'fc-128', week: 'week1', topic: 'Edge Cases', front: 'Can a professional refuse instructions on ethical grounds without legal protection?', back: 'The professional codes say YES as a moral obligation — BCS says public interest overrides employer authority. But the LEGAL protection (PIDA 1998) only applies to "qualifying disclosures" in specific categories. A computing professional who refuses to implement an AI bias system cannot rely on PIDA unless they can characterise it as a legal breach. This is a dangerous gap. The professional may be morally right but legally exposed to dismissal. 90%+ answer: acknowledge this gap and argue for expanded whistleblower protection in tech.', type: 'application', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-129', week: 'week6', topic: 'AI Ethics', front: 'What is algorithmic bias and why is it a professional ethics issue?', back: 'When ML models produce systematically different outputs for different demographic groups — often perpetuating historical discrimination. Examples: Amazon hiring AI (2018) penalised women\'s CVs; facial recognition higher error rates for dark-skinned faces; predictive policing feedback loops. LEGAL EXPOSURE: Equality Act 2010 prohibits indirect discrimination in employment decisions — algorithmic bias may constitute indirect discrimination. Professional obligation: BCS s.1 and ACM 1.4 require fair and unbiased treatment. Testing for bias before deployment is now a professional requirement.', type: 'application', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-130', week: 'week2', topic: 'AI Ethics', front: 'What is the EU AI Act and how does it interact with UK GDPR?', back: 'EU AI Act (2024): first comprehensive AI regulation. Classifies AI by risk: unacceptable (banned: social scoring, subliminal manipulation); high-risk (facial recognition, hiring AI, credit scoring) — require conformity assessment, human oversight, accuracy/transparency; limited risk; minimal risk. UK position: not bound but "aligning where appropriate." GDPR interaction: high-risk AI systems likely trigger Art. 35 DPIA; automated decisions → Art. 22. Professional obligation: building high-risk AI without impact assessment is now potentially illegal in EU markets.', type: 'law', difficulty: 'hard', examRelevance: 'high' },

  // ===================== EXAMINER TRAP FLASHCARDS =====================
  { id: 'fc-131', week: 'week1', topic: 'Examiner Traps', front: 'TRAP: A student writes "Under the BCS Code, professionals must follow laws." What\'s wrong with this?', back: 'This conflates legal compliance with professional ethics. The BCS Code goes BEYOND law — it requires acting in the PUBLIC INTEREST even when the law does not require it. The correct statement: "The BCS Code requires public interest as the paramount duty, which may require action beyond legal compliance and may occasionally require action contrary to employer instructions." Never say professional codes just require law-following — that misses the entire point of having professional codes.', type: 'mistake', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-132', week: 'week2', topic: 'Examiner Traps', front: 'TRAP: A student cites "GDPR" for cookie consent. Why does this lose marks?', back: 'Cookie consent is governed by PECR 2003 (Privacy and Electronic Communications Regulations) — not GDPR. GDPR governs what happens with the DATA collected via cookies. Correct: "PECR 2003 requires prior informed consent before placing non-essential cookies. The data then collected is processed under UK GDPR." Citing GDPR for the consent mechanism is a knowledge error that signals surface-level understanding to the examiner. High-mark answers correctly distinguish PECR (consent) from GDPR (processing).', type: 'mistake', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-133', week: 'week3', topic: 'Examiner Traps', front: 'TRAP: Student says "software cannot be patented in the UK." What\'s the more accurate answer?', back: 'Software "as such" cannot be patented — but software that provides a TECHNICAL SOLUTION TO A TECHNICAL PROBLEM CAN be patented if it meets the Aerotel four-step test. This is a common oversimplification that loses marks. Correct: "The Patents Act 1977 excludes programs for computers as such, but post-Aerotel/Macrossan, software demonstrating a technical effect beyond normal program execution may be patentable." The nuance distinguishes a 2:1 answer from a first-class answer.', type: 'mistake', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-134', week: 'week6', topic: 'Examiner Traps', front: 'TRAP: A student writes "authorised penetration testing is always legal." What\'s missing?', back: 'NOT ALWAYS. Authorisation from the SYSTEM OWNER does not protect against: (1) third-party systems accessed during testing — scope creep; (2) testing shared hosting/cloud infrastructure affects other tenants without their consent; (3) CMA still applies to accidental access outside scope; (4) Personal data encountered during testing — GDPR still requires careful handling. Correct: "Written authorisation from the system owner negates the CMA S.1 mens rea for the defined scope, but does not create a blanket licence — scope, proportionality, and data handling obligations remain."', type: 'mistake', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-135', week: 'week9', topic: 'Examiner Traps', front: 'TRAP: Student says "employees can consent to monitoring for GDPR purposes." What\'s wrong?', back: 'For most MONITORING PURPOSES: no. GDPR consent must be freely given — the power imbalance in employment makes this impossible for most monitoring. ICO guidance is explicit: consent is unlikely to be a valid lawful basis for employee monitoring. Alternative: legitimate interests (with full balancing test) or legal obligation. EXCEPTION: Art. 9 special category data (biometrics) cannot use employment consent at all — a different Art. 9(2) exemption must be identified. High-mark answer: explain BOTH why consent fails AND which alternative applies.', type: 'mistake', difficulty: 'hard', examRelevance: 'high' },

  // ===================== SYNTHESIS/HIGH-MARK CARDS =====================
  { id: 'fc-136', week: 'week1', topic: 'Synthesis', front: 'Synthesise: how do the three main ethical theories complement each other in professional computing?', back: 'They are COMPLEMENTARY, not competitive. Utilitarianism identifies outcomes and stakeholders affected. Deontology establishes categorical professional duties that outcomes cannot override. Virtue ethics describes the professional CHARACTER that would apply both theories wisely. A purely utilitarian engineer might sacrifice privacy for aggregate convenience; a purely deontological one might follow rules rigidly even when catastrophic; a virtue ethicist might have good intentions but no analytical framework. 90%+ answer synthesises all three and shows professional codes draw on all three.', type: 'application', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-137', week: 'week2', topic: 'Synthesis', front: 'How do the seven GDPR principles interrelate? Show the dependency chain.', back: 'P1 (Lawfulness) provides the authorisation for all processing — the foundation. P2 (Purpose Limitation) constrains WHAT can be done with authorised data. P3 (Minimisation) constrains HOW MUCH data can be collected. P4 (Accuracy) ensures the data is fit for purpose. P5 (Storage Limitation) sets the time boundary. P6 (Integrity/Confidentiality) secures the data while in use. P7 (Accountability) is the META-PRINCIPLE enforcing all others — without P7, the other six are aspirational, not binding. Understanding the dependency chain is what separates 90%+ answers.', type: 'application', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-138', week: 'week6', topic: 'Synthesis', front: 'How does the CIA Triad map to the CMA 1990 provisions?', back: 'CONFIDENTIALITY breaches → CMA S.1 (unauthorised access to read/exfiltrate data). INTEGRITY breaches → CMA S.3 (unauthorised modification — ransomware, data manipulation). AVAILABILITY attacks → CMA S.3 (impairment of computer function) + S.3ZA for critical infrastructure. S.3A (creating attack tools) enables all three. The CIA Triad is the security FRAMEWORK; the CMA is the LEGAL RESPONSE to violations. Using both in an answer shows technical and legal synthesis — the precise combination examiners want for 90%+ marks.', type: 'application', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-139', week: 'week5', topic: 'Synthesis', front: 'How does the LORS IG framework connect to GDPR accountability?', back: 'LORS (Legal, Operational, Reputational, Strategic) failure modes map directly to GDPR: Legal risk = fines (£17.5M) + criminal liability; Operational risk = GDPR P4 (accuracy) — poor data quality impairs lawful processing; Reputational risk = Art. 34 (individual notification amplifies public knowledge of breach); Strategic risk = organisations without IG cannot demonstrate P7 (accountability). The connection: IG is not just about legal compliance — it is the organisational infrastructure that makes GDPR compliance possible.', type: 'application', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-140', week: 'week9', topic: 'Synthesis', front: 'Connect PTLN monitoring test → GDPR → professional ethics: give the full analysis of an employer requesting keystroke logging', back: 'Step 1 PTLN: P — is it proportionate? Blanket keystroke logging for all staff fails unless specific high-risk role. T — are employees informed via explicit written policy? N — cannot achieve the same outcome (productivity verification) less intrusively? L — legitimate business purpose documented? Step 2 GDPR: Art. 6 lawful basis (legitimate interests — must pass balancing test); Art. 5(1)(c) minimisation; Art. 13/14 transparency obligation. Step 3 Professional ethics: IT implementer has independent professional duty to refuse unlawful instructions — BCS s.1. Full chain: PTLN fails → GDPR unlawful → professional refuses → BCS protects.', type: 'application', difficulty: 'hard', examRelevance: 'high' },

  // ===================== WEEK 3/5 AI/GOVERNANCE EXPANSION =====================
  { id: 'fc-141', week: 'week3', topic: 'AI & IP', front: 'Is training an AI model on copyrighted data infringement?', back: 'CONTESTED — currently litigated. In the UK: TDM (Text and Data Mining) exception permits mining for non-commercial research (CDPA s.29A). Commercial TDM: controversial — Getty Images v Stability AI pending. Government proposed broader TDM exception (2022) then withdrew after creative industry opposition. EU: AI Act requires disclosure of training data; certain Copyright Directive obligations. Professional obligation: document training data provenance; assess copyright exposure in commercial AI products; consider licensing agreements.', type: 'application', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-142', week: 'week5', topic: 'AI Governance', front: 'What are the key components of an AI governance framework?', back: 'RISK ASSESSMENT: identify potential harms before deployment (bias audit, safety testing). TRANSPARENCY: explain decisions; document training data and model architecture. HUMAN OVERSIGHT: ensure humans can review, override, or correct AI decisions (especially Art. 22 GDPR for automated decisions). ACCOUNTABILITY: named individual responsible for AI systems. MONITORING: ongoing performance measurement post-deployment. DATA GOVERNANCE: GDPR-compliant data use. UK National AI Strategy emphasises "trustworthy AI" — aligned with AI Act principles even outside EU scope.', type: 'framework', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-143', week: 'week1', topic: 'Value-Sensitive Design', front: 'What is Value-Sensitive Design (VSD) and how does it apply to professional codes?', back: 'VSD (Batya Friedman, 1990s): systematic approach to incorporating human values (wellbeing, privacy, autonomy, democracy) into technical design from the outset. Three investigations: CONCEPTUAL (identify stakeholders + values), EMPIRICAL (user research), TECHNICAL (evaluate design alternatives). Relevance to BCS/ACM: VSD is the engineering methodology that operationalises "public interest" and "avoid harm" into design practice. Computing professionals who do not perform VSD risk delivering systems that are technically functional but ethically harmful.', type: 'application', difficulty: 'hard', examRelevance: 'medium' },
  { id: 'fc-144', week: 'week2', topic: 'Privacy Theory', front: 'What is contextual integrity (Nissenbaum) and why does it matter for GDPR?', back: 'Helen Nissenbaum (2004): privacy is not about secrecy but about appropriate information flow — "information flows appropriately when they match the norms of the context in which information was originally shared." Medical info shared with doctor flows appropriately to specialists; sharing it with employers violates contextual norms even if technically "public." Relevance: GDPR purpose limitation (P2) and legitimate interests balancing test both implicitly use contextual integrity — information shared in one context cannot be repurposed without consent.', type: 'application', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-145', week: 'week6', topic: 'Threat Intelligence', front: 'What is threat intelligence and how does it inform a security governance framework?', back: 'Actionable, evidence-based knowledge about threats to an organisation — including TTPs (tactics, techniques, procedures) of specific threat actors. Levels: strategic (high-level trends — C-suite briefings), operational (upcoming campaigns), tactical (specific IOCs — IP addresses, hashes). Sources: NCSC, ISACs, commercial feeds (Recorded Future), OSINT. Governance application: threat intelligence should DRIVE security investment decisions — organisations facing HUHT adversaries need different controls to those facing LULT attackers. Uninformed security spending wastes resources.', type: 'framework', difficulty: 'hard', examRelevance: 'medium' },
  { id: 'fc-146', week: 'week1', topic: 'Deep Philosophy', front: 'Explain Aristotle\'s "practical wisdom" (phronesis) and its application to computing professionals', back: 'Phronesis: the virtue of practical wisdom — the ability to discern the right course of action in particular circumstances. Cannot be reduced to rule-following. Relevant when: professional codes conflict, ethical theories give different answers, novel technology creates unprecedented dilemmas. Computing professionals must exercise phronesis when: AI creates genuine uncertainty, multiple stakeholders have conflicting legitimate interests, available options all involve harm. 90%+ answers cite phronesis when discussing why professional codes cannot be merely technical — they require moral judgement.', type: 'application', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-147', week: 'week5', topic: 'Governance', front: 'What is accountability diffusion and how did it contribute to the Post Office Horizon scandal?', back: 'Accountability diffusion: when responsibility is distributed across many parties to the extent that no single party feels fully accountable for an outcome. Post Office Horizon: Post Office managers assumed Fujitsu\'s system was accurate; Fujitsu developers assumed Post Office management knew of bugs; Post Office legal team assumed the technical evidence was reliable. Result: 900+ wrongful prosecutions for 14 years. IG lesson: accountability must be NAMED and UNDELEGATABLE — the Post Office IT inquiry called for a designated "AI/system accountability officer." Generic "team responsibility" = accountability diffusion = nobody accountable.', type: 'casestudy', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-148', week: 'week3', topic: 'Open Source Ethics', front: 'What are the ethical arguments for and against open source software?', back: 'FOR: transparency (security researchers can audit for vulnerabilities); community innovation; knowledge commons; prevents vendor lock-in; aligns with virtue ethics of sharing. AGAINST: "tragedy of the commons" in maintenance — XZ Utils (2024) showed critical infrastructure depending on one unpaid volunteer; quality inconsistency; no warranty/liability. Ethical tension: organisations that profit from open source but do not contribute back are free-riding — violates ACM Code of fair treatment. This debate is directly relevant to the module\'s theme of professional responsibility.', type: 'application', difficulty: 'hard', examRelevance: 'high' },
  { id: 'fc-149', week: 'week6', topic: 'Nation-State', front: 'Why is nation-state cyber attribution so difficult and what are the ethical implications for computing professionals?', back: 'TECHNICAL: attribution requires: multiple independent corroborating indicators, analysis of TTPs, SIGINT/HUMINT collaboration, forensic evidence. False flags possible — attacker can plant evidence pointing to another state. False attribution: risks diplomatic incidents or military escalation. ETHICAL IMPLICATION FOR PROFESSIONALS: (1) security researchers must maintain epistemic humility when attributing attacks publicly; (2) "Lazarus Group attribution" means accepting imperfect certainty — publish responsibly; (3) CMA enforcement against foreign state actors: practically impossible — but that does not reduce moral culpability.', type: 'application', difficulty: 'hard', examRelevance: 'high' },
];
